#include <iostream>
#include "llvm/IR/Verifier.h"
#include "llvm/IR/IRBuilder.h"
#include "llvm/IR/LLVMContext.h"
#include "llvm/IR/Module.h"
#include "llvm/IR/Function.h"
#include "llvm/IR/BasicBlock.h"

using namespace llvm;

int main() {
  LLVMContext Context;
  Module M("test", Context);
  IRBuilder<> Builder(Context);

  // Create a simple function
  FunctionType *FT = FunctionType::get(Type::getInt64Ty(Context), false);
  Function *F = Function::Create(FT, Function::ExternalLinkage, "test", M);

  // Create basic blocks
  BasicBlock *BB = BasicBlock::Create(Context, "bb", F);
  BasicBlock *BB1 = BasicBlock::Create(Context, "bb1", F);
  BasicBlock *BB5 = BasicBlock::Create(Context, "bb5", F);
  BasicBlock *BB6 = BasicBlock::Create(Context, "bb6", F);

  // Build IR similar to the test case
  Builder.SetInsertPoint(BB);
  Builder.CreateBr(BB1);

  Builder.SetInsertPoint(BB1);
  PHINode *Phi = Builder.CreatePHI(Type::getInt32Ty(Context), 2);
  PHINode *Phi2 = Builder.CreatePHI(Type::getInt32Ty(Context), 2);
  Value *Or = Builder.CreateOr(Phi, ConstantInt::get(Type::getInt32Ty(Context), 0));
  Value *Add = Builder.CreateAdd(ConstantInt::get(Type::getInt32Ty(Context), 0), 
                                 ConstantInt::get(Type::getInt32Ty(Context), 0));
  Value *Or3 = Builder.CreateOr(Add, Phi2);
  Value *Or4 = Builder.CreateOr(Or3, ConstantInt::get(Type::getInt32Ty(Context), 0));
  Builder.CreateBr(BB5);

  Builder.SetInsertPoint(BB5);
  Value *Cond = ConstantInt::getFalse(Context);
  Builder.CreateCondBr(Cond, BB6, BB1);

  Builder.SetInsertPoint(BB6);
  PHINode *Phi7 = Builder.CreatePHI(Type::getInt32Ty(Context), 1);
  PHINode *Phi8 = Builder.CreatePHI(Type::getInt32Ty(Context), 1);
  Builder.CreateRet(ConstantInt::get(Type::getInt64Ty(Context), 0));

  // Add incoming values
  Phi->addIncoming(ConstantInt::get(Type::getInt32Ty(Context), 0), BB);
  Phi->addIncoming(Or, BB5);
  Phi2->addIncoming(ConstantInt::get(Type::getInt32Ty(Context), 0), BB);
  Phi2->addIncoming(Or4, BB5);
  Phi7->addIncoming(Or, BB5);
  Phi8->addIncoming(Or3, BB5);

  // Verify the module
  std::string Error;
  raw_string_ostream OS(Error);
  if (verifyModule(M, &OS)) {
    std::cout << "Error: " << Error << std::endl;
  } else {
    std::cout << "Module is valid" << std::endl;
  }

  return 0;
}
EOF
```

